sql:
SELECT mall_type, AVG(total_sqft) AS average_total_sqft
FROM shopping_centers
GROUP BY mall_type;

SELECT COUNT(DISTINCT visitor_id) 
FROM visitor_devices 
WHERE device_imei = 'your_imei_number';

SELECT device_type, COUNT(*) AS number_of_devices
FROM devices
GROUP BY device_type;

SELECT COUNT(visit_id) AS total_visits
FROM visits
WHERE date BETWEEN '2022-01-01' AND '2022-12-31';

SELECT name AS "Shopping Center Name", contact_email AS "Contact Email"
FROM shopping_centers
WHERE total_sqft = (
    SELECT MAX(total_sqft) 
    FROM shopping_centers
);

external_knowledge:
- "Major shopping centers" refers to the well-known shopping centers with significant foot traffic;
- "Behavioral actions" here means the actions recorded by the system, such as the time spent;
- "Demographic diversity" indicates the variety of visitor demographics present in the shopping center;
- "Frequency of visits" refers to how often each device is recorded as visiting the shopping center.

